// FACIS Simulation RNG — deterministic, JS-native.
//
// Mirrors src/core/random_generator.py:
//   entity seed key  : "{base_seed}:{entity_id}"
//   tick seed key    : "{base_seed}:{entity_id}:{timestamp_ms}"
//   sha256 → first 8 bytes (16 hex chars) → seedrandom.alea(seedHex)
//
// Output stream is NOT byte-identical to numpy PCG64 (documented break).
// The seeding strategy is identical so call sites map 1:1.
//
// Inputs (msg.payload):
//   base_seed     (number, optional — defaults to subflow env BASE_SEED)
//   entity_id     (string, optional — defaults to "default")
//   timestamp_ms  (number, optional — defaults to 0; pass to scope per tick)
//   action        (string)  one of: uniform | normal | gauss | int | choice | sequence
//   params        (object)  per-action parameters (see switch below)
//
// Output (msg.payload):
//   value, seed_hash, base_seed, entity_id, timestamp_ms, action

const baseSeed =
    (msg.payload && typeof msg.payload.base_seed === 'number')
        ? msg.payload.base_seed
        : Number(env.get('BASE_SEED') || 12345);
const entityId = (msg.payload && msg.payload.entity_id) || 'default';
const tsMs =
    (msg.payload && typeof msg.payload.timestamp_ms === 'number')
        ? msg.payload.timestamp_ms
        : 0;
const action = (msg.payload && msg.payload.action) || 'uniform';
const params = (msg.payload && msg.payload.params) || {};

const seedKey = String(baseSeed) + ':' + String(entityId) + ':' + String(tsMs);
const seedHex = crypto.createHash('sha256').update(seedKey).digest('hex').slice(0, 16);
const rng = seedrandom.alea(seedHex);

let value;
switch (action) {
    case 'uniform': {
        const min = (typeof params.min === 'number') ? params.min : 0;
        const max = (typeof params.max === 'number') ? params.max : 1;
        value = min + (max - min) * rng();
        break;
    }
    case 'normal':
    case 'gauss': {
        const mean = (typeof params.mean === 'number') ? params.mean : 0;
        const stddev = (typeof params.stddev === 'number') ? params.stddev : 1;
        let u = 0;
        let v = 0;
        while (u === 0) u = rng();
        while (v === 0) v = rng();
        const z = Math.sqrt(-2 * Math.log(u)) * Math.cos(2 * Math.PI * v);
        value = mean + stddev * z;
        break;
    }
    case 'int': {
        const min = Math.ceil((typeof params.min === 'number') ? params.min : 0);
        const max = Math.floor((typeof params.max === 'number') ? params.max : 1);
        value = Math.floor(rng() * (max - min + 1)) + min;
        break;
    }
    case 'choice': {
        const items = Array.isArray(params.items) ? params.items : [];
        if (items.length === 0) {
            node.error('rng: choice action requires non-empty params.items', msg);
            return null;
        }
        value = items[Math.floor(rng() * items.length)];
        break;
    }
    case 'sequence': {
        const count = (typeof params.count === 'number') ? params.count : 1;
        const seq = [];
        for (let i = 0; i < count; i += 1) seq.push(rng());
        value = seq;
        break;
    }
    default:
        node.error('rng: unknown action ' + action, msg);
        return null;
}

msg.payload = {
    value: value,
    seed_hash: seedHex,
    base_seed: baseSeed,
    entity_id: entityId,
    timestamp_ms: tsMs,
    action: action
};
return msg;
